import{_ as t,c as o,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Предупреждение ToS: риски для аккаунта и рекомендации по безопасности | Antigravity Auth","description":"Узнайте о рисках использования плагина Antigravity Auth и методах безопасности аккаунта. Поймите критические сценарии, механизмы теневой блокировки и отличия от ограничения скорости, освоите стратегии управления несколькими аккаунтами, контролем использования и подготовкой аккаунта.","frontmatter":{"title":"Предупреждение ToS: риски для аккаунта и рекомендации по безопасности | Antigravity Auth","sidebarTitle":"Не позволяйте заблокировать аккаунт","subtitle":"Предупреждение ToS: риски для аккаунта и рекомендации по безопасности","description":"Узнайте о рисках использования плагина Antigravity Auth и методах безопасности аккаунта. Поймите критические сценарии, механизмы теневой блокировки и отличия от ограничения скорости, освоите стратегии управления несколькими аккаунтами, контролем использования и подготовкой аккаунта.","tags":["FAQ","Риски и предупреждения","Безопасность аккаунта"],"prerequisite":["start-quick-install"],"order":5},"headers":[],"relativePath":"ru/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md","filePath":"ru/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"}'),r={name:"ru/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"};function e(n,l,s,d,h,g){return a(),o("div",null,[...l[0]||(l[0]=[i('<h1 id="предупреждение-tos" tabindex="-1">Предупреждение ToS <a class="header-anchor" href="#предупреждение-tos" aria-label="Permalink to &quot;Предупреждение ToS&quot;">​</a></h1><p>После изучения этого урока вы узнаете о рисках использования плагина Antigravity Auth и способах защиты вашего Google аккаунта.</p><h2 id="ваша-текущая-ситуация" tabindex="-1">Ваша текущая ситуация <a class="header-anchor" href="#ваша-текущая-ситуация" aria-label="Permalink to &quot;Ваша текущая ситуация&quot;">​</a></h2><p>Вы рассматриваете использование плагина Antigravity Auth для доступа к AI-моделям Google Antigravity, но у вас есть опасения:</p><ul><li>Вы видели сообщения в сообществе о заблокированных или теневых банах аккаунтов</li><li>Вы беспокоитесь, что использование неофициальных инструментов нарушает условия обслуживания Google</li><li>Вы не уверены, следует ли использовать новый или старый аккаунт</li><li>Вы хотите узнать, как снизить риски</li></ul><p>Эти опасения обоснованы. Любое использование неофициальных инструментов сопряжено с определенными рисками. Эта статья поможет вам понять конкретные точки риска и стратегии их смягчения.</p><h2 id="когда-нужно-прочитать-этот-урок" tabindex="-1">Когда нужно прочитать этот урок <a class="header-anchor" href="#когда-нужно-прочитать-этот-урок" aria-label="Permalink to &quot;Когда нужно прочитать этот урок&quot;">​</a></h2><ul><li><strong>Перед установкой плагина</strong>: узнайте о рисках, прежде чем принять решение об использовании</li><li><strong>При выборе аккаунта</strong>: решите, какой Google аккаунт использовать для аутентификации</li><li><strong>При столкновении с блокировкой</strong>: узнайте о возможных причинах и профилактических мерах</li><li><strong>При регистрации нового пользователя</strong>: избегайте высокорисковых моделей использования</li></ul><hr><h2 id="обзор-основных-рисков" tabindex="-1">Обзор основных рисков <a class="header-anchor" href="#обзор-основных-рисков" aria-label="Permalink to &quot;Обзор основных рисков&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Важное предупреждение</p><p><strong>Использование этого плагина может нарушать Условия обслуживания Google (Terms of Service).</strong></p><p>Некоторые пользователи сообщили, что их Google аккаунты были заблокированы или подверглись теневому бану (Shadow Ban — ограничение доступа без явного уведомления).</p><p><strong>Используя этот плагин, вы принимаете следующие заявления:</strong></p><ol><li>Это неофициальный инструмент, не одобренный или не поддерживаемый Google</li><li>Ваш Google аккаунт может быть приостановлен или заблокирован навсегда</li><li>Вы несете все риски и последствия использования этого плагина</li></ol></div><h3 id="что-такое-теневои-бан" tabindex="-1">Что такое теневой бан? <a class="header-anchor" href="#что-такое-теневои-бан" aria-label="Permalink to &quot;Что такое теневой бан?&quot;">​</a></h3><p><strong>Теневой бан (Shadow Ban)</strong> — это ограничительная мера, применяемая Google к подозрительным аккаунтам. В отличие от прямой блокировки, теневой бан не отображает явных сообщений об ошибке, а:</p><ul><li>API-запросы возвращают ошибки 403 или 429</li><li>Квота отображается как доступная, но фактически не может быть использована</li><li>Другие аккаунты работают нормально, только отмеченный аккаунт затронут</li></ul><p>Теневой бан обычно длится дольше (от нескольких дней до нескольких недель) и не может быть восстановлен через апелляцию.</p><hr><h2 id="критические-сценарии" tabindex="-1">Критические сценарии <a class="header-anchor" href="#критические-сценарии" aria-label="Permalink to &quot;Критические сценарии&quot;">​</a></h2><p>Следующие сценарии значительно увеличивают риск отметки или блокировки аккаунта:</p><h3 id="🚨-сценарии-1-совершенно-новыи-google-аккаунт" tabindex="-1">🚨 Сценарий 1: совершенно новый Google аккаунт <a class="header-anchor" href="#🚨-сценарии-1-совершенно-новыи-google-аккаунт" aria-label="Permalink to &quot;🚨 Сценарий 1: совершенно новый Google аккаунт&quot;">​</a></h3><p><strong>Уровень риска: крайне высокий</strong></p><p>Использование этого плагина с только что зарегистрированным Google аккаунтом имеет очень высокую вероятность блокировки. Причины:</p><ul><li>Новые аккаунты не имеют исторических данных о поведении и легко отмечаются системой обнаружения злоупотреблений Google</li><li>Большое количество API-запросов на новом аккаунте рассматривается как аномальное поведение</li><li>Google более строго проверяет новые аккаунты</li></ul><p><strong>Рекомендация</strong>: Не создавайте новый аккаунт специально для этого плагина.</p><h3 id="🚨-сценарии-2-новыи-аккаунт-подписка-pro-ultra" tabindex="-1">🚨 Сценарий 2: новый аккаунт + подписка Pro/Ultra <a class="header-anchor" href="#🚨-сценарии-2-новыи-аккаунт-подписка-pro-ultra" aria-label="Permalink to &quot;🚨 Сценарий 2: новый аккаунт + подписка Pro/Ultra&quot;">​</a></h3><p><strong>Уровень риска: крайне высокий</strong></p><p>Только что зарегистрированный аккаунт с немедленной подпиской на сервисы Pro или Ultra от Google часто отмечается и блокируется. Причины:</p><ul><li>Модель высокого использования после подписки на новом аккаунте выглядит как злоупотребление</li><li>Google более строго проверяет новых платных пользователей</li><li>Этот шаблон слишком сильно отличается от пути роста нормального пользователя</li></ul><p><strong>Рекомендация</strong>: Дайте аккаунту «естественно расти» в течение некоторого времени (по крайней мере, несколько месяцев), прежде чем рассматривать подписку.</p><h3 id="🟡-сценарии-3-множество-запросов-за-короткое-время" tabindex="-1">🟡 Сценарий 3: множество запросов за короткое время <a class="header-anchor" href="#🟡-сценарии-3-множество-запросов-за-короткое-время" aria-label="Permalink to &quot;🟡 Сценарий 3: множество запросов за короткое время&quot;">​</a></h3><p><strong>Уровень риска: высокий</strong></p><p>Инициирование большого количества API-запросов за короткое время или частое использование параллельных прокси/многих сессий вызывает ограничение скорости и обнаружение злоупотреблений. Причины:</p><ul><li>Шаблон запросов OpenCode более интенсивен, чем в нативных приложениях (вызовы инструментов, повторы, потоковая передача и т.д.)</li><li>Высокая конкуренция запросов вызывает защитный механизм Google</li></ul><p><strong>Рекомендации</strong>:</p><ul><li>Контролируйте частоту запросов и уровень параллелизма</li><li>Избегайте одновременного запуска множества параллельных агентов</li><li>Используйте ротацию нескольких аккаунтов для распределения запросов</li></ul><h3 id="🟡-сценарии-4-использование-единственного-google-аккаунта" tabindex="-1">🟡 Сценарий 4: использование единственного Google аккаунта <a class="header-anchor" href="#🟡-сценарии-4-использование-единственного-google-аккаунта" aria-label="Permalink to &quot;🟡 Сценарий 4: использование единственного Google аккаунта&quot;">​</a></h3><p><strong>Уровень риска: средний</strong></p><p>Если у вас только один Google аккаунт и вы полагаетесь на него для доступа к критическим сервисам (Gmail, Drive и т.д.), риск выше. Причины:</p><ul><li>Блокировка аккаунта повлияет на вашу ежедневную работу</li><li>Невозможно восстановить через апелляцию</li><li>Отсутствие планового резерва</li></ul><p><strong>Рекомендация</strong>: Используйте отдельный аккаунт, который не зависит от критических сервисов.</p><hr><h2 id="рекомендации-по-лучшим-практикам" tabindex="-1">Рекомендации по лучшим практикам <a class="header-anchor" href="#рекомендации-по-лучшим-практикам" aria-label="Permalink to &quot;Рекомендации по лучшим практикам&quot;">​</a></h2><h3 id="✅-рекомендуемые-деиствия" tabindex="-1">✅ Рекомендуемые действия <a class="header-anchor" href="#✅-рекомендуемые-деиствия" aria-label="Permalink to &quot;✅ Рекомендуемые действия&quot;">​</a></h3><p><strong>1. Используйте установленный Google аккаунт</strong></p><p>Приоритетно выберите Google аккаунт, который использовался в течение некоторого времени (рекомендуется 6 месяцев и более):</p><ul><li>Имеет нормальную историю использования сервисов Google (Gmail, Drive, Google Search и т.д.)</li><li>Без исторических нарушений</li><li>Аккаунт привязан к номеру телефона и прошел проверку</li></ul><p><strong>2. Настройте несколько аккаунтов</strong></p><p>Добавьте несколько Google аккаунтов и распределите запросы через ротацию:</p><ul><li>Настройте хотя бы 2-3 аккаунта</li><li>Используйте стратегию <code>account_selection_strategy: &quot;hybrid&quot;</code> (по умолчанию)</li><li>При столкновении с ограничением скорости автоматически переключайте аккаунты</li></ul><p><strong>3. Контролируйте использование</strong></p><ul><li>Избегайте плотных запросов за короткое время</li><li>Уменьшите количество параллельных агентов</li><li>В <code>antigravity.json</code> установите <code>max_rate_limit_wait_seconds: 0</code> для быстрого сбоя вместо повтора</li></ul><p><strong>4. Мониторинг состояния аккаунта</strong></p><p>Регулярно проверяйте состояние аккаунта:</p><ul><li>Просмотрите <code>rateLimitResetTimes</code> в <code>~/.config/opencode/antigravity-accounts.json</code></li><li>Включите журналы отладки: <code>OPENCODE_ANTIGRAVITY_DEBUG=1 opencode</code></li><li>При столкновении с ошибками 403/429 приостановите использование на 24-48 часов</li></ul><p><strong>5. Сначала «разогрейтесь» на официальном интерфейсе</strong></p><p>Эффективный метод, сообщенный пользователями сообщества:</p><ol><li>Войдите в <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a> в браузере</li><li>Запустите несколько простых промптов (например, «Привет», «Сколько будет 2+2»)</li><li>После 5-10 успешных вызовов используйте плагин</li></ol><p><strong>Принцип</strong>: Использование аккаунта через официальный интерфейс заставит Google думать, что это нормальное поведение пользователя, снижая риск отметки.</p><h3 id="❌-деиствия-которых-следует-избегать" tabindex="-1">❌ Действия, которых следует избегать <a class="header-anchor" href="#❌-деиствия-которых-следует-избегать" aria-label="Permalink to &quot;❌ Действия, которых следует избегать&quot;">​</a></h3><ul><li>❌ Создавать совершенно новый Google аккаунт специально для этого плагина</li><li>❌ Немедленно подписываться на Pro/Ultra на только что зарегистрированном аккаунте</li><li>❌ Использовать единственный критический сервисный аккаунт (например, рабочий email)</li><li>❌ Повторять попытки после срабатывания ограничения 429</li><li>❌ Одновременно запускать множество параллельных агентов</li><li>❌ Вносить <code>antigravity-accounts.json</code> в систему контроля версий</li></ul><hr><h2 id="часто-задаваемые-вопросы" tabindex="-1">Часто задаваемые вопросы <a class="header-anchor" href="#часто-задаваемые-вопросы" aria-label="Permalink to &quot;Часто задаваемые вопросы&quot;">​</a></h2><h3 id="в-мои-аккаунт-заблокирован-могу-ли-я-подать-апелляцию" tabindex="-1">В: Мой аккаунт заблокирован, могу ли я подать апелляцию? <a class="header-anchor" href="#в-мои-аккаунт-заблокирован-могу-ли-я-подать-апелляцию" aria-label="Permalink to &quot;В: Мой аккаунт заблокирован, могу ли я подать апелляцию?&quot;">​</a></h3><p><strong>О: Нет.</strong></p><p>Если блокировка или теневой бан вызваны обнаружением злоупотреблений Google через этот плагин, обычно невозможно восстановить через апелляцию. Причины:</p><ul><li>Блокировка автоматически срабатывает на основе шаблона использования API</li><li>Google придерживается строгого отношения к использованию неофициальных инструментов</li><li>При подаче апелляции нужно объяснить назначение инструмента, но сам этот плагин может быть признан нарушением</li></ul><p><strong>Рекомендации</strong>:</p><ul><li>Используйте другие незатронутые аккаунты</li><li>Если все аккаунты заблокированы, используйте напрямую <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a></li><li>Избегайте дальнейших попыток на заблокированном аккаунте</li></ul><h3 id="в-будет-ли-мои-аккаунт-обязательно-заблокирован-при-использовании-этого-плагина" tabindex="-1">В: Будет ли мой аккаунт обязательно заблокирован при использовании этого плагина? <a class="header-anchor" href="#в-будет-ли-мои-аккаунт-обязательно-заблокирован-при-использовании-этого-плагина" aria-label="Permalink to &quot;В: Будет ли мой аккаунт обязательно заблокирован при использовании этого плагина?&quot;">​</a></h3><p><strong>О: Не обязательно.</strong></p><p>Большинство пользователей не столкнулись с проблемами при использовании этого плагина. Риск зависит от:</p><ul><li>Возраста аккаунта и исторического поведения</li><li>Частоты использования и шаблона запросов</li><li>Следования ли лучшим практикам</li></ul><p><strong>Оценка риска</strong>:</p><ul><li>Старый аккаунт + умеренное использование + ротация нескольких аккаунтов → низкий риск</li><li>Новый аккаунт + плотные запросы + один аккаунт → высокий риск</li></ul><h3 id="в-в-чем-разница-между-теневым-баном-и-ограничением-скорости" tabindex="-1">В: В чем разница между теневым баном и ограничением скорости? <a class="header-anchor" href="#в-в-чем-разница-между-теневым-баном-и-ограничением-скорости" aria-label="Permalink to &quot;В: В чем разница между теневым баном и ограничением скорости?&quot;">​</a></h3><p><strong>О: Существенно отличаются, и методы восстановления тоже разные.</strong></p><table tabindex="0"><thead><tr><th>Характеристика</th><th>Теневой бан</th><th>Ограничение скорости (429)</th></tr></thead><tbody><tr><td>Причина срабатывания</td><td>Обнаружение злоупотреблений, отмечено как подозрительное</td><td>Частота запросов превышает квоту</td></tr><tr><td>Код ошибки</td><td>403 или тихий сбой</td><td>429 Too Many Requests</td></tr><tr><td>Продолжительность</td><td>От нескольких дней до нескольких недель</td><td>От нескольких часов до одного дня</td></tr><tr><td>Метод восстановления</td><td>Невозможно восстановить, нужно использовать другие аккаунты</td><td>Ожидание сброса или переключение аккаунтов</td></tr><tr><td>Можно ли предотвратить</td><td>Следуйте лучшим практикам для снижения риска</td><td>Контролируйте частоту запросов</td></tr></tbody></table><h3 id="в-можно-ли-использовать-корпоративныи-google-аккаунт" tabindex="-1">В: Можно ли использовать корпоративный Google аккаунт? <a class="header-anchor" href="#в-можно-ли-использовать-корпоративныи-google-аккаунт" aria-label="Permalink to &quot;В: Можно ли использовать корпоративный Google аккаунт?&quot;">​</a></h3><p><strong>О: Не рекомендуется.</strong></p><p>Корпоративные аккаунты обычно привязаны к критическим сервисам и данным, блокировка имеет более серьезные последствия. Кроме того:</p><ul><li>Корпоративные аккаунты проверяются более строго</li><li>Может нарушать IT-политику компании</li><li>Риск берется на себя лично, но влияет на команду</li></ul><p><strong>Рекомендация</strong>: Используйте личный аккаунт.</p><h3 id="в-могут-ли-несколько-аккаунтов-полностью-избежать-блокировки" tabindex="-1">В: Могут ли несколько аккаунтов полностью избежать блокировки? <a class="header-anchor" href="#в-могут-ли-несколько-аккаунтов-полностью-избежать-блокировки" aria-label="Permalink to &quot;В: Могут ли несколько аккаунтов полностью избежать блокировки?&quot;">​</a></h3><p><strong>О: Не могут полностью избежать, но могут снизить влияние.</strong></p><p>Роль нескольких аккаунтов:</p><ul><li>Распределяют запросы, снижая вероятность того, что один аккаунт вызовет ограничение</li><li>Если один аккаунт заблокирован, другие аккаунты все еще доступны</li><li>При столкновении с ограничением автоматически переключает, повышая доступность</li></ul><p><strong>Но несколько аккаунтов не являются «защитным амулетом»</strong>:</p><ul><li>Если все аккаунты вызовут обнаружение злоупотреблений, все могут быть заблокированы</li><li>Не злоупотребляйте несколькими аккаунтами для плотных запросов</li><li>Каждый аккаунт все еще должен следовать лучшим практикам</li></ul><hr><h2 id="контрольные-точки-✅" tabindex="-1">Контрольные точки ✅ <a class="header-anchor" href="#контрольные-точки-✅" aria-label="Permalink to &quot;Контрольные точки ✅&quot;">​</a></h2><p>После прочтения этого урока вы должны знать:</p><ul><li>[ ] Использование этого плагина может нарушать Google ToS, риск берете на себя</li><li>[ ] Новый аккаунт + подписка Pro/Ultra — это критический сценарий</li><li>[ ] Рекомендуется использовать установленный Google аккаунт</li><li>[ ] Настройка нескольких аккаунтов может распределить риск</li><li>[ ] После блокировки аккаунта невозможно восстановить через апелляцию</li><li>[ ] Важно контролировать частоту запросов и использование</li></ul><hr><h2 id="резюме-урока" tabindex="-1">Резюме урока <a class="header-anchor" href="#резюме-урока" aria-label="Permalink to &quot;Резюме урока&quot;">​</a></h2><p>В этом уроке рассматриваются потенциальные риски использования плагина Antigravity Auth:</p><ol><li><strong>Ключевые риски</strong>: может нарушать Google ToS, аккаунт может быть заблокирован или теневой бан</li><li><strong>Критические сценарии</strong>: новый аккаунт, новый аккаунт + подписка, плотные запросы, один критический аккаунт</li><li><strong>Лучшие практики</strong>: используйте старый аккаунт, настройте несколько аккаунтов, контролируйте использование, мониторинг состояния, сначала «разогрейтесь»</li><li><strong>Часто задаваемые вопросы</strong>: невозможно апеллировать, риск зависит от человека, несколько аккаунтов могут снизить влияние</li></ol><p>Перед использованием этого плагина, пожалуйста, внимательно оцените риски. Если вы не можете принять последствие возможной блокировки аккаунта, рекомендуется напрямую использовать <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a>.</p><hr><h2 id="приложение-ссылки-на-исходныи-код" tabindex="-1">Приложение: ссылки на исходный код <a class="header-anchor" href="#приложение-ссылки-на-исходныи-код" aria-label="Permalink to &quot;Приложение: ссылки на исходный код&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть местоположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-23</p></blockquote><p>Содержание этого урока основано на разделе предупреждений о рисках в документации README проекта (README.md:23-40), не затрагивает конкретную реализацию кода.</p><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Заявление о предупреждении ToS</td><td><a href="https://github.com/NoeFabris/opencode-antigravity-auth/blob/main/README.md#L23-L40" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>23-40</td></tr></tbody></table></details>',99)])])}const c=t(r,[["render",e]]);export{u as __pageData,c as default};
